import{_ as e,o as t,c as a,ae as r}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"AI Daily Blog 今日必读 Top 3 - 2026-04-18","description":"","frontmatter":{},"headers":[],"relativePath":"2026-04-18-AI-Daily-Blog/AI-Daily-Blog-Top.md","filePath":"2026-04-18-AI-Daily-Blog/AI-Daily-Blog-Top.md"}'),n={name:"2026-04-18-AI-Daily-Blog/AI-Daily-Blog-Top.md"};function p(s,o,l,i,g,h){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="ai-daily-blog-今日必读-top-3-2026-04-18" tabindex="-1">AI Daily Blog 今日必读 Top 3 - 2026-04-18 <a class="header-anchor" href="#ai-daily-blog-今日必读-top-3-2026-04-18" aria-label="Permalink to &quot;AI Daily Blog 今日必读 Top 3 - 2026-04-18&quot;">​</a></h1><blockquote><p>每日精选 3 篇最重要文章，附完整正文中文翻译</p></blockquote><hr><h2 id="_1-llm-在训练过程中如何变得更加连贯" tabindex="-1">1. <a href="https://www.gilesthomas.com/2026/04/how-an-llm-becomes-more-coherent-over-training" target="_blank" rel="noreferrer">LLM 在训练过程中如何变得更加连贯</a> <a class="header-anchor" href="#_1-llm-在训练过程中如何变得更加连贯" aria-label="Permalink to &quot;1. [LLM 在训练过程中如何变得更加连贯](https://www.gilesthomas.com/2026/04/how-an-llm-becomes-more-coherent-over-training)&quot;">​</a></h2><p><strong>推荐理由</strong>：用可视化方式直观展示 GPT-2 风格模型随训练推进的输出演变</p><p><strong>来源</strong>: Giles Thomas</p><p><strong>发布时间</strong>: 2026-04-17</p><hr><h3 id="完整正文" tabindex="-1">完整正文 <a class="header-anchor" href="#完整正文" aria-label="Permalink to &quot;完整正文&quot;">​</a></h3><p>当我回顾 2015 年 Andrej Karpathy 关于 RNN 的文章时，发现他给出了一个关于训练过程中输出如何改善的例子。那么对于一个（相对）现代的基于 Transformer 的大语言模型来说，这会是怎样的呢？</p><p>我最近训练了一个 GPT-2-small 风格的大语言模型，拥有 1.63 亿参数，在 FineWeb 数据集的约 32 亿个 token 上进行训练。</p><p><strong>关键发现</strong></p><p>作者在训练过程中保存了 57 个检查点，并用相同的提示「Every effort moves you」对每个检查点进行测试，以观察进展。</p><p>训练开始前，模型输出的完全是混乱的 token 沙拉。</p><p>到了 step 617（相当于看了 6000 万个 token），模型学会了常见 token 的组合。</p><p>到了 step 1234，语义开始显现。</p><p>到了 step 2468，模型开始生成连贯的文本。</p><p>令人惊讶的是，到了 step 9255——仅完成三分之一的训练——模型就已经能够生成「相当连贯的文本」。剩余的训练主要用于提高质量，而非建立基础一致性。</p><p><strong>演变示例</strong></p><ul><li><strong>Step 2468</strong>: &quot;Every effort moves you to a different country. For all the most part, a world map can only see the world map&quot;</li><li><strong>Step 28382</strong>: &quot;Every effort moves you, however, towards a better future, and that&#39;s what counts as a win.&quot;</li><li><strong>最终 (step 33164)</strong>: &quot;Every effort moves you, and you&#39;re rewarded, but not to your potential. You&#39;ve got to&quot;</li></ul><p><strong>观察与思考</strong></p><p>作者指出，小型模型往往倾向于重复和俗套的励志内容。这篇文章强调，虽然连贯性发展很快，但剩余训练的目的是提高准确性——「当你让它续写『法国的首都是』时，它会回答『巴黎』，而不是一个连贯但错误的答案，比如『鲁昂』」。</p><hr><h2 id="_2-许多反-ai-论点实际上是保守主义论点" tabindex="-1">2. <a href="https://seangoedecke.com/many-anti-ai-arguments-are-conservative/" target="_blank" rel="noreferrer">许多反 AI 论点实际上是保守主义论点</a> <a class="header-anchor" href="#_2-许多反-ai-论点实际上是保守主义论点" aria-label="Permalink to &quot;2. [许多反 AI 论点实际上是保守主义论点](https://seangoedecke.com/many-anti-ai-arguments-are-conservative/)&quot;">​</a></h2><p><strong>推荐理由</strong>：犀利分析当前 AI 批评话语的政治倾向与意识形态根源</p><p><strong>来源</strong>: Sean Goedecke</p><p><strong>发布时间</strong>: 2026-04-18</p><hr><h3 id="完整正文-1" tabindex="-1">完整正文 <a class="header-anchor" href="#完整正文-1" aria-label="Permalink to &quot;完整正文&quot;">​</a></h3><p>大多数反 AI 言论都是左翼编码的。主流的 AI 批评将其描述为 techno-fascism（技术法西斯主义）的工具，或者诉诸于左翼主要关注的碳排放、劳动者权益等议题。</p><p>但仔细观察这些论点时，我发现它们实际上与保守主义立场有着深刻的共鸣。</p><p><strong>版权论点：历史上的左翼反对派</strong></p><p>版权法传统上是左翼和右翼都支持的法律领域——左翼支持创作者权益，右翼支持知识产权保护。然而，反 AI 阵营中大量使用的反版权论点，实际上在历史上是左翼反对的对象。</p><p><strong>人类创造力作为本质价值</strong></p><p>反 AI 论述中一个核心主题是人类创造力作为「本质价值」的地位。但这正是保守主义的核心主张——传统、习俗和本质主义价值观是社会根基。</p><p><strong>职业保护主义</strong></p><p>传统上，右翼往往支持自由市场，反对对特定职业的保护。而当前许多反 AI 论述中关于「保护工作岗位」的论点，恰恰是职业保护主义的体现——这在历史上更多是保守主义的主张。</p><p><strong>前沿 AI 模型本身的左翼倾向</strong></p><p>一个有趣的现象是，最强大的 AI 模型（来自 Anthropic、Google、OpenAI）本身在政治倾向上是左翼的。这与当前政治格局形成了有趣的对比。</p><p><strong>为什么会这样？</strong></p><p>作者分析了左翼转向反 AI 的几个原因：</p><ol><li>科技 CEO 们在 2024 年整体向右转</li><li>加密货币狂潮引发的反弹</li><li>特朗普的亲 AI 立场引发了党派性反弹</li><li>环保议题与传统政治分歧的结合</li></ol><p><strong>结论</strong></p><p>作者认为，当前的这种政治联盟是不稳定的。问题是：是否会有一批右翼的反 AI 声音出现，将左翼推向支持 AI 的立场？或者反 AI 情绪会成为一个新的党派分化议题？</p><hr><h2 id="_3-qwen3-6-35b-a3b-在我的笔记本上画出了比-claude-opus-4-7-更好的鹈鹕" tabindex="-1">3. <a href="https://simonwillison.net/2026/Apr/16/qwen-beats-opus/" target="_blank" rel="noreferrer">Qwen3.6-35B-A3B 在我的笔记本上画出了比 Claude Opus 4.7 更好的鹈鹕</a> <a class="header-anchor" href="#_3-qwen3-6-35b-a3b-在我的笔记本上画出了比-claude-opus-4-7-更好的鹈鹕" aria-label="Permalink to &quot;3. [Qwen3.6-35B-A3B 在我的笔记本上画出了比 Claude Opus 4.7 更好的鹈鹕](https://simonwillison.net/2026/Apr/16/qwen-beats-opus/)&quot;">​</a></h2><p><strong>推荐理由</strong>：开源模型挑战闭源巨头，Simon Willison 的 pelican benchmark 再添新数据点</p><p><strong>来源</strong>: Simon Willison</p><p><strong>发布时间</strong>: 2026-04-16</p><hr><h3 id="完整正文-2" tabindex="-1">完整正文 <a class="header-anchor" href="#完整正文-2" aria-label="Permalink to &quot;完整正文&quot;">​</a></h3><p>对于任何一直在认真对待 Karpathy 的「鹈鹕骑自行车」作为模型鲁棒性测试的人来说，这里是今早两个重要模型发布的结果——来自阿里巴巴的 Qwen3.6-35B-A3B 和来自 Anthropic 的 Claude Opus 4.7。</p><p>我通过 LM Studio 在我的 MacBook Pro M5 上本地运行 Qwen3.6（21GB 量化模型），然后使用相同的 SVG 生成提示对两个模型进行了测试。</p><p><strong>测试 1：鹈鹕骑自行车</strong></p><p>Qwen 生成的 SVG 中自行车框架形状正确，而 Opus 4.7 则错误地渲染了框架。</p><p><strong>测试 2：火烈鸟骑独轮车</strong></p><p>我用「火烈鸟骑独轮车」的提示再次测试；Qwen 添加了太阳镜和领结等创意细节，而 Opus 生成了一幅更常规的插图。</p><p><strong>关于基准测试的说明</strong></p><p>Willison 强调，这个基准测试是一个幽默的演示，而非严格的评估。他指出，尽管 Qwen 的 SVG 输出更好，但它是一个 21GB 的量化模型，不太可能匹配 Opus 4.7 的整体能力——但具体到在自行车上画鹈鹕的 SVG 插图，在笔记本上运行的 Qwen3.6 目前优于闭源模型。</p><hr><p><em>Generated by AI Daily Blog - 2026-04-18</em></p>',61)])])}const d=e(n,[["render",p]]);export{c as __pageData,d as default};
